var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"다들 정지.","JPN":"みな、止まれ。","ENG":"Halt.","TWN":"大家都停下。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이제 곧 마지막 전투가 치러질 테니 정비를 해두어라.","JPN":"もうすぐ最後の戦闘が始まる、各自整備しておくように。","ENG":"Make preparations, for the final battle is about to commence.","TWN":"最後一戰即將打響，務必做好準備。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"바로 저 탑이 우리의 태양을 앗아간 마왕의 소굴이군요.","JPN":"あの塔が私たちの太陽を奪った魔王の巣窟なんですね。","ENG":"That tower is the lair of the Demon Lord who stole our sun.","TWN":"那座塔是偷走我們太陽的魔王巢穴。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"저기에 들어가서… 살아 돌아올 수 있을까요?","JPN":"あそこに入って……生きて帰れるんでしょうか？","ENG":"Will we... make it out of there alive?","TWN":"去那裡……能活著出來嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_CAP","text":{"KOREA":"승리를 의심할 것 없다. 우리 곁엔 예하께서 함께 하시니까.","JPN":"勝利を疑う必要はない。私たちには猊下がおられる。","ENG":"Do not doubt our victory. Her Eminence is on our side.","TWN":"我們的勝利毋庸置疑。因為主教與我們同在。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_CAP","text":{"KOREA":"우리의 믿음이 굳건한 이상, 에클레시아님은 그 어떤 강적에게도 패하지 않으신다.","JPN":"私たちの信仰が堅いのであれば、エクレシア様はいかなる強敵にも負けない。","ENG":"As long as our faith is strong, Her Eminence will not submit to any formidable foe.","TWN":"只要我們的信仰堅定，艾可露西亞就不會敗給任何強敵。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"그렇겠죠.","JPN":"そうですね。","ENG":"I believe so too.","TWN":"當然。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"하지만 이곳에 오는 동안 벌써 열 명이 넘는 전사들이 마물들에게 죽었습니다.","JPN":"しかしここに来るまでに、すでに10人以上の戦士たちが魔物に殺されました。","ENG":"However, ten of our men have already fallen on our way here.","TWN":"但這一路已經有十幾名戰士被惡魔殺死了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"다음은 제가 될지도 모르죠.","JPN":"次は私が殺されるのかもしれません。","ENG":"It will be no surprise if I am next.","TWN":"也許我就是下一個。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"전 그저, 마왕의 칼날이 노리는 게 제 목이 될까 두렵습니다.","JPN":"私はただ、魔王の剣が自分の首を狙ってくるのではないかと怖いんです。","ENG":"I just... fear that it will be my head at the end of the Demon Lord's blade.","TWN":"我只是害怕魔王的利刃會瞄準我的脖子。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_CAP","text":{"KOREA":"그런 불경한 말은 삼가라!","JPN":"そんな不敬な言葉は慎め！","ENG":"Such blasphemy!","TWN":"不要說這種不敬之言！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"에클레시아님! 저, 저는 더 이상 싸우고 싶지 않습니다!","JPN":"エクレシア様！　わ、私はこれ以上は戦いたくありません！","ENG":"Your Eminence! I... I do not wish to fight anymore!","TWN":"艾可露西亞！我、我不想再打了！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"예하께서 마왕을 꺾고 태양을 되찾는다 한들, 제 죽음은 영원한 어둠일 뿐이잖습니까!","JPN":"猊下が魔王に打ち勝ち、太陽を取り戻したとしても、私が死ねば永遠の闇が訪れるだけないじゃないですか！","ENG":"Though you may defeat the Demon Lord and retrieve our sun, I will be in eternal darkness if I die!","TWN":"即使您打敗魔王奪回了太陽，我卻只會在永遠的黑暗中迎來死亡！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_CAP","text":{"KOREA":"네놈! 우리의 성무를 모독하는 것이냐!","JPN":"貴様！　私たちの聖務を冒涜するつもりか！","ENG":"You! How dare you taint our sacred duty?!","TWN":"你！你竟敢褻瀆我們的聖務！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L19_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"열 사람 모두 추악하고 끔찍한 몰골로 죽었습니다!","JPN":"10人全員が、ひどく残酷な姿で死んでいきました！","ENG":"Ten of our men have already died gruesome deaths!","TWN":"十個人都死得很慘！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"정말 저희들의 그 참혹한 죽음 너머에 빛의 낙원이 있긴 한 건가요?!","JPN":"本当に、私たちのあんな残酷な死の向こうに光の楽園が存在するのですか！？","ENG":"Is there truly a paradise of light beyond a horrific death like that?!","TWN":"在我們那慘烈的死亡彼處，是否真的有一個光明的樂園？！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_CAP","text":{"KOREA":"아무래도 역병의 기운에 너무 오랫동안 사로잡힌 것 같군.","JPN":"どうやら長い間疫病に晒されてしまったようだな。","ENG":"It seems that you have been exposed to the plague for too long.","TWN":"看來你已經被瘟疫侵蝕太久了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_CAP","text":{"KOREA":"저 부정한 자를 끌어내라!","JPN":"あの不届きものを追い出せ！","ENG":"Drag that faithless man out!","TWN":"拉出那個不淨之人！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그만!","JPN":"やめろ！","ENG":"Enough!","TWN":"停！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"고개를 들어라, 이로니우스.","JPN":"頭を上げろ、イロニウス。","ENG":"Raise your head, Ironius.","TWN":"抬起頭來，伊羅尼斯。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"예하께서 제 이름을 어떻게…","JPN":"猊下が私の名前をどうして……","ENG":"Your Eminence, how do you know my name...?","TWN":"主教怎麼會知道我的名字……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그대는 네 동생을 치료하기 위해 순례단에 자원했지. 그 아이를 지키기 위해서, 그렇지 않나?","JPN":"そなたは妹を治療するため巡礼団に志願した者だったな。その子を守るため、そうではないか？","ENG":"You joined the pilgrimage to treat your ill sister. To protect her. Did you not?","TWN":"你為了治療你的妹妹自願加入朝聖團，不是嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"네… 그렇습니다.","JPN":"はい……そのとおりです。","ENG":"Yes... That is correct.","TWN":"是的……沒錯。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"여기 있는 이들 모두가 그대와 마찬가지로 고향에 지켜야 할 가족을 두고 온 사람들이다.","JPN":"ここにいる者は皆そなたと同じく、故郷に守るべき家族を置いてきた者たちであろう。","ENG":"Much like you, those around you all have families back home they hope to protect.","TWN":"和你們一樣，這裡的所有人都把需要保護的家人留在家鄉了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"우리가 여기서 겁에 질려 물러선다면, 그땐 우리가 아닌 고향의 가족들이 위험하겠지.","JPN":"ここで我らが怯えて引き下がると、その時は我々ではなく故郷にいる家族が危なくなるのだ。","ENG":"If we flee with our tail between our legs, then it will be our families back home who will suffer next.","TWN":"如果我們再次畏縮退縮，那麼會面臨危險的不是我們，而是我們的家人。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"알고… 있습니다.","JPN":"わかって……おります。","ENG":"Yes... I know.","TWN":"我知道……我知道。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"하지만, 앞서 죽어 나간 팔라딘들의 비명이 아직도 생생합니다.","JPN":"でも、今まで死んでしまったパラディンたちの悲鳴がまだ耳に残っています。","ENG":"However, the screams of those fallen paladins still haunt me.","TWN":"但是，之前犧牲的那些聖騎士的慘叫聲依然在我耳邊徘徊。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"아무리 신서의 구절을 되뇌어도… 두려움이 가시질 않습니다.","JPN":"いくら神書の言葉を口にしても……恐怖心をぬぐえません。","ENG":"No matter how much I recite the holy script... I am not relieved of this fear.","TWN":"無論我重複默誦多少次經文……恐懼依然消失。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그렇다면 내 이름을 걸고 약속하겠다.","JPN":"ならば、我の名にかけて誓おう。","ENG":"Then I swear on my name.","TWN":"既然這樣，那我以自己的名義向你保證。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"마왕이 너희의 목을 노리지 못하도록, 내 목숨을 걸어서라도 지키리라.","JPN":"魔王がそなたたちの首を狙えないよう、我の命をかけてでも守ろう。","ENG":"I shall protect you with my life, so the Demon Lord cannot come for your head.","TWN":"我會用我的性命從魔王的魔爪中保護你們。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"아아…….","JPN":"ああ……","ENG":"Ah...","TWN":"啊啊……"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"감사합니다, 예하.","JPN":"ありがとうございます、猊下。","ENG":"Thank you, Your Eminence.","TWN":"謝謝主教。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"감사합니다… 감사합니다…!","JPN":"ありがとうございます……ありがとうございます……！","ENG":"Thank you... Thank you...!","TWN":"謝謝……謝謝……！"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"뭐하는 거지, 이로니우스?","JPN":"何をしているのだ、イロニウス？","ENG":"What are you doing, Ironius?","TWN":"你在幹什麼，伊羅尼斯？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"망설이면 네 소중한 동생은 내 손에 죽는다.","JPN":"惑っているとそなたの大切な妹は我の手で殺されるのだ。","ENG":"Your hesitation will be the death of your precious sister.","TWN":"如果你猶豫不決，你的寶貝妹妹就會死在我手裡。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>오빠… 제발 말을 들어. 날 죽일 셈이야?</color>","JPN":"<color=#ffd34c>お兄ちゃん……お願い、言うことを聞いて。私を殺すつもりなの？</color>","ENG":"<color=#ffd34c>Ironius... Please listen to me. Are you going to let me die?</color>","TWN":"<color=#ffd34c>哥哥……求求你聽話，你要害死我嗎？</color>"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L50_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"아아아… 안돼! 제발! 내 동생만큼은…!","JPN":"あああ……ダメだ！　頼む！　妹だけは……！","ENG":"Aaahh... No! Please! Spare my sister...!","TWN":"啊……不！求你了！別把我妹妹……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"명심하렴, 불쌍한 소녀의 오라비야. 내 다음 공격이 너에겐 마지막 기회란다.","JPN":"忘れるな、可哀想な少女の兄よ。我の次の攻撃がそなたの最後のチャンスである。","ENG":"Mark my words, brother of the pitiful girl. My next attack will be your last chance.","TWN":"記住，可憐女孩的哥哥，我的下一次攻擊是你最後的機會。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"겉모습에 현혹되지 말아라! 저건 타기리온이 만들어낸 인형일 뿐이다!","JPN":"外見に惑わされるな！　あれはタギリオンが作った人形に過ぎない！","ENG":"Do not be fooled by her appearance! That is merely a doll made by Thagirion!","TWN":"別被外表迷惑了，那只是塔基里翁製造的傀儡！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"큭…!","JPN":"くっ……！","ENG":"Khh...!","TWN":"咳……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"이로니우스… 어째서 나를…","JPN":"イロニウス……どうして我を……","ENG":"Ironius... Why have you...","TWN":"伊羅尼斯……你為何……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_NONAME","text":{"KOREA":"죄송합니다…! 예하! 죄송합니다!","JPN":"申し訳ございません……！　猊下！　申し訳ございません！","ENG":"I'm sorry...! Your Eminence! I'm sorry!","TWN":"對不起……！主教！對不起！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"아하하, 어리석구나.","JPN":"アハハ、愚かだな。","ENG":"Ah hah hah, what a fool you are.","TWN":"哈哈哈，愚蠢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"진정으로 소중한 것 앞에서는 너희 인간이 부르짖는 신앙 따위 아무짝에도 쓸모없거늘.","JPN":"真に大切なものの前では、そなたたち人間が謳う信仰などは何の役にも立たないのだ。","ENG":"What you humans call faith is useless when something truly important is at stake.","TWN":"在真正珍貴的東西面前，你們人類口中的信仰一文不值。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"으윽….","JPN":"ううっ……","ENG":"Ngh...","TWN":"呃……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L16_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_CAP","text":{"KOREA":"예하…!","JPN":"猊下……！","ENG":"Your Eminence...!","TWN":"主教……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MUSK_HARMONY_NULL_CAP","text":{"KOREA":"예하를 모시고 밖으로 탑을 떠나라! 내가 시간을 벌겠다!","JPN":"猊下を連れて外へ、塔から離れろ！　私が時間を稼ぐ！","ENG":"Take Her Eminence and leave the tower! I'll buy you some time!","TWN":"帶著主教離開！我來爭取時間！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY_SOFT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"아, 여기 계셨네요.","JPN":"あ、ここにいらっしゃったのですね。","ENG":"Oh, there you are.","TWN":"啊，你在這裡。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…날 찾고 있었던 건가?","JPN":"……我を探していたのか？","ENG":"...You were looking for me?","TWN":"……你在找我嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"네! 밥이 다 됐는데 안 보이셔서 걱정했어요!","JPN":"はい！　ご飯ができたのに見当たらなくて心配しました！","ENG":"Yup! The food is all done, but I couldn't find you, so I got worried!","TWN":"是的！飯已經好了，卻沒見到你！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"예하가 드실 것도 이렇게 가져왔어요! 좀 식긴 했지만요.","JPN":"猊下が召し上がるものもちゃんと持ってきましたよ！　ちょっと冷めてしまいましたけど。","ENG":"I brought you your share, Your Eminence! But the food's gone a little cold.","TWN":"我給主教帶了些吃的！雖然有些涼了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그렇군. 시신을 태우는 연기 때문에 일부러 멀리까지 왔건만.","JPN":"そうか。遺体を燃やしている煙のせいでわざと遠くまで来たのだが。","ENG":"I see. I came out all the way here because of the fumes from the burning corpses.","TWN":"是嗎，我是因為燒屍體時冒出的煙故意跑這麼遠來的。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"괜한 수고를 하게 해서 미안하구나.","JPN":"苦労をかけてすまないな。","ENG":"I am sorry to have made you come all this way.","TWN":"辛苦你了。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"괜찮아요. 전 걷는 거 좋아하거든요.","JPN":"大丈夫です。私は歩くのが好きなんですよ。","ENG":"It's all right. I like walking anyway.","TWN":"沒關係，我喜歡走路。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"그런데, 여기에 꽂아 두신 검들은 뭐죠?","JPN":"ところで、ここに刺さっている剣は何ですか？","ENG":"But what are those swords plunged into the ground for?","TWN":"對了，插在這裡的劍是什麼呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"지난 성전에서 마왕 타기리온에게 희생된 순례단의 묘비다.","JPN":"以前の聖戦で魔王タギリオンによって犠牲になった巡礼団の墓だ。","ENG":"This is the pilgrimage graveyard for those who were killed by the Demon Lord Thagirion in the previous holy war.","TWN":"是為了在上次聖戰被魔王塔基里翁殺害的朝聖團立下的墓碑。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그대가 함께 맞서 싸워준 덕분에 이들의 희생을 기릴 수 있게 됐어.","JPN":"そなたが一緒に戦ってくれたおかげで彼らの犠牲を称えることができた。","ENG":"Thanks to your help in fighting her, I am now able to pay my respects to them.","TWN":"多虧你與我並肩作戰，他們的犧牲才能變得更有意義。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"엘리시온을 대표해 감사를 표하마.","JPN":"エリシオンの代表として礼を言おう。","ENG":"I would like to speak on behalf of Elysion and express our gratitude.","TWN":"我代表艾利森感謝你。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"괜찮아요.","JPN":"いいんです。","ENG":"It's okay.","TWN":"不用謝我。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"그 사람이 보여준 언니의 모습이 너무 진짜 같아서 깜빡 속을 뻔했지만…","JPN":"魔王が見せたお姉さんの姿があまりにも本物のようで、うっかり騙されかけたんですが……","ENG":"I was almost fooled by her tricks when she showed me a convincing image of my sister...","TWN":"只是那個人製造的傀儡和姊姊長得太像了，我差點被騙了……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"언니라면 분명 자길 위해 다른 사람을 희생시키라는 말은 하지 않았을 테니까요!","JPN":"きっとお姉さんなら自分のために他人を犠牲にしろとは言わなかったはずです！","ENG":"But my sister would never tell me to sacrifice others for her!","TWN":"但如果是姊姊，絕對不會讓我為了自己而犧牲別人！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"그 말만으로도 그대의 누이가 그대에게 얼마나 자랑스러운 존재인지 어렴풋이 알겠구나.","JPN":"その言葉だけでそなたの姉がそなたにとって、どれほど誇らしい存在なのかよくわかる。","ENG":"That alone shows me how proud you are of your sister.","TWN":"從這句話，我就能知道你的姊姊對你而言是多麼自豪的存在。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"신전으로 돌아가면 형제자매들에게 그대 누이의 행방을 수소문하라 일러 둘 것이니 안심하거라.","JPN":"神殿に戻ったら兄弟姉妹たちにそなたの姉の行方を探すよう言っておく。案ずるな。","ENG":"Rest assured. Once we return to the temple, I will order the brothers and sisters to go look for your sister.","TWN":"等回到聖殿，我會讓弟兄姊妹多打聽你姊姊的行蹤。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"정말요? 고맙습니다, 에클레시아님!","JPN":"本当ですか？　ありがとうございます、エクレシア様！","ENG":"Really? Thank you, Miss Ecclesia!","TWN":"真的嗎？謝謝你，艾可露西亞！"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"아앗, 또 괴물이라니.","JPN":"ああっ、また化け物だなんて。","ENG":"Huh? Monsters again?","TWN":"哎唷，又是怪物。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DASH_HORIZON_EX_NAME","text":{"KOREA":"설마 제 음식 냄새를 맡고 온 건 아니겠죠?","JPN":"まさかご飯の匂いにつられて来たんじゃないでしょうね？","ENG":"They're not here because of the smell of my food, right?","TWN":"難道是聞到了我帶來的食物的味道？"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"죽은 자들의 성흔 냄새를 맡은 것이다.","JPN":"死者の聖痕の匂いについてきたのであろう。","ENG":"They have caught the scent of Stigmata from the corpses.","TWN":"他聞到了死者的聖痕氣息。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_EX_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"물러서 있어라, 소녀여.","JPN":"さがれ、少女よ。","ENG":"Stand back, girl.","TWN":"你退下。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_CA_NULL","text":{"KOREA":"순례단의 숭고한 안식을 방해하는 것들은 내 손으로 정리할 테니.","JPN":"巡礼団の崇高なる安寧を妨げるものは我の手で片付けてやろう。","ENG":"I will get rid of those who disrupt the sacred slumber of the pilgrimage myself.","TWN":"我將親手清除那些打擾朝聖團安息的東西。"},"stage":{"bg":"COUNTERSIDE_FOREST","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};